async function storGet(k){ try{ const r=await window.storage.get(k); return r?JSON.parse(r.value):null; }catch{ return null; } }
async function storSet(k,v){ try{ await window.storage.set(k,JSON.stringify(v)); }catch{} }

async function readSheet(tab) {
  const url = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&headers=1&sheet=${encodeURIComponent(tab)}&t=${Date.now()}`;
  try {
    const res  = await fetch(url);
    const text = await res.text();
    const json = JSON.parse(text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1));
    const table = json.table;
    if (!table || !table.rows) return null;
    // Use label if available, fall back to id; preserve original casing
    const headers = table.cols.map(c => (c.label || c.id || "").trim());
    return table.rows.map(row => {
      const obj = {};
      headers.forEach((h, i) => {
        const cell = row.c && row.c[i];
        const val  = cell ? (cell.v !== null && cell.v !== undefined ? cell.v : '') : '';
        obj[h]                           = val;  // original:   "Full Name"
        obj[h.toLowerCase()]             = val;  // lowercase:  "full name"
        obj[h.replace(/\s+/g,"")]        = val;  // no spaces:  "FullName"
        obj[h.toLowerCase().replace(/\s+/g,"")] = val; // lower+nospace: "fullname"
      });
      return obj;
    });
  } catch(e) { return null; }
}

// ── Offline queue helpers ─────────────────────────────────────────────────────
// Writes are queued locally first, then flushed to the Sheet when online.
// Queue persists in window.storage so pending actions survive page refresh.
const QUEUE_KEY = "ng-offline-queue";

async function queueLoad(){ return await storGet(QUEUE_KEY)||[]; }
async function queueSave(q){ await storSet(QUEUE_KEY, q); }

async function scriptPost(payload) {
  if (!SCRIPT_URL) return { ok: false };
  try {
    const res = await fetch(SCRIPT_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'text/plain;charset=utf-8' },
      body: JSON.stringify(payload),
    });
    return await res.json();
  } catch(e) { return { ok: false, error: String(e) }; }
}

// Queue a write — saves locally immediately, attempts flush if online
async function queueWrite(payload, flushFn) {
  if (navigator.onLine) {
    // Try direct write first
    const res = await scriptPost(payload);
    if (res?.ok) return true;
  }
  // Offline or write failed — add to queue
  const q = await queueLoad();
  q.push({ payload, ts: Date.now() });
  await queueSave(q);
  if (flushFn) flushFn();
  return false;
}

// Flush all queued writes to the Sheet
async function flushQueue(onProgress) {
  const q = await queueLoad();
  if (!q || q.length === 0) return 0;
  const remaining = [];
  let flushed = 0;
  for (const item of q) {
    const res = await scriptPost(item.payload);
    if (res?.ok) { flushed++; }
    else { remaining.push(item); }
  }
  await queueSave(remaining);
  if (onProgress) onProgress(remaining.length);
  return flushed;
}

